package org.apache.commons.csv;

import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = new StringBuilder();
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrintRecord_withMultipleValues() throws IOException {
        printer.printRecord("value1", 123, null, "value4");

        String printed = out.toString();
        // The exact output depends on CSVFormat and internal print methods,
        // so just verify that output is not empty and contains the values
        // in some form (since print is public and called).
        // We can't assert exact output without CSVFormat details.
        assert !printed.isEmpty();
        assert printed.contains("value1") || printed.contains("123") || printed.contains("value4");
    }

    @Test
    void testPrintRecord_withNoValues() throws IOException {
        printer.printRecord();

        String printed = out.toString();
        // Should print just a newline (println)
        // We expect output length > 0 because println adds line ending
        assert printed.length() > 0;
    }

    @Test
    void testPrintRecord_invokesPrintAndPrintln() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Spy on printer to verify internal calls
        CSVPrinter spyPrinter = Mockito.spy(new CSVPrinter(out, format));

        spyPrinter.printRecord("abc");

        verify(spyPrinter, times(1)).print("abc");
        verify(spyPrinter, times(1)).println();
    }

    @Test
    void testPrivatePrintMethodInvocation() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        Method privatePrint = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        privatePrint.setAccessible(true);

        // Call private print with a sample CharSequence and offsets
        privatePrint.invoke(printer, "obj", "value", 0, 5);

        // No exception means success, output should contain "value"
        String printed = out.toString();
        assert printed.length() > 0;
    }

    @Test
    void testPrivatePrintAndEscapeInvocation() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        Method privatePrintAndEscape = CSVPrinter.class.getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class);
        privatePrintAndEscape.setAccessible(true);

        privatePrintAndEscape.invoke(printer, "escapeTest", 0, 10);

        String printed = out.toString();
        assert printed.length() > 0;
    }

    @Test
    void testPrivatePrintAndQuoteInvocation() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        Method privatePrintAndQuote = CSVPrinter.class.getDeclaredMethod("printAndQuote", Object.class, CharSequence.class, int.class, int.class);
        privatePrintAndQuote.setAccessible(true);

        privatePrintAndQuote.invoke(printer, "obj", "quotedValue", 0, 11);

        String printed = out.toString();
        assert printed.length() > 0;
    }
}
